import React from 'react';

const PlaylistCard = ({ playlist, onEdit, onDelete }) => {
  return (
    <div className="w-full max-w-4xl bg-slate-800/80 backdrop-blur-md border border-slate-700 rounded-xl p-6 shadow-lg hover:bg-slate-700/80 transition">
      <div className="flex justify-between items-start">
        <div>
          <h2 className="text-xl font-semibold text-white">{playlist.title}</h2>
          {playlist.description && (
            <p className="text-slate-300 mt-1">{playlist.description}</p>
          )}
          <p className="text-slate-400 text-sm mt-2">
            {playlist.videoCount || 0} videos
          </p>
        </div>

        <div className="flex gap-2">
          <button
            onClick={onEdit}
            className="bg-slate-600 hover:bg-slate-500 text-white px-3 py-1 rounded text-sm"
          >
            Edit
          </button>
          <button
            onClick={onDelete}
            className="bg-red-500/80 hover:bg-red-500 text-white px-3 py-1 rounded text-sm"
          >
            Delete
          </button>
        </div>
      </div>
    </div>
  );
};

export default PlaylistCard;
